cls = inst.__class__
attrs = fields(cls)
for a in attrs:
    if not a.init:
        continue
    attr_name = a.name  # To deal with private attributes.
    init_name = a.alias
    if init_name not in changes:
        changes[init_name] = getattr(inst, attr_name)

return cls(**changes)
